(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.50in left #> placebo "Placebo" 1.50in right #> zom_50mg "Zomerane 50 mg" 1.50in right #> zom_100mg "Zomerane 100 mg" 1.50in right #> total "All Subjects" 1.50in right #> group "group" 0.90in left #> Header: valign=bottom, N-counts  ## ── Auto-width: let the engine calculate ─────────────────────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic"),     .width = "auto"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.70in left #> placebo "placebo" 0.97in left #> zom_50mg "zom_50mg" 0.97in left #> zom_100mg "zom_100mg" 0.97in left #> total "total" 0.97in left #> group "group" 0.90in left #> Header: valign=bottom  ## ── Percentage widths: responsive to page size ───────────────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic", width = "30%"),     zom_50mg       = fr_col("Zomerane 50mg",  width = "17.5%", align = "right"),     zom_100mg      = fr_col("Zomerane 100mg", width = "17.5%", align = "right"),     placebo        = fr_col("Placebo",         width = "17.5%", align = "right"),     total          = fr_col("Total",           width = "17.5%", align = "right")   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 30% left #> placebo "Placebo" 18% right #> zom_50mg "Zomerane 50mg" 18% right #> zom_100mg "Zomerane 100mg" 18% right #> total "Total" 18% right #> group "group" 0.90in left #> Header: valign=bottom  ## ── Fit mode: fill the full page width proportionally ────────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic"),     .width = "fit"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 3.24in left #> placebo "placebo" 1.17in left #> zom_50mg "zom_50mg" 1.17in left #> zom_100mg "zom_100mg" 1.17in left #> total "total" 1.17in left #> group "group" 1.08in left #> Header: valign=bottom  ## ── Equal-width distribution ─────────────────────────────────────────────  # Stub column fixed at 2.5in; remaining columns share the rest equally tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic", width = 2.5),     .width = "equal"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.50in left #> placebo "placebo" 1.30in left #> zom_50mg "zom_50mg" 1.30in left #> zom_100mg "zom_100mg" 1.30in left #> total "total" 1.30in left #> group "group" 1.30in left #> Header: valign=bottom  ## ── Label transform: underscores to spaces + title case ──────────────────  tbl_demog |>   fr_table() |>   fr_cols(.label_fn = ~ tools::toTitleCase(gsub("_", " ", .x))) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.70in left #> placebo "Placebo" 0.97in left #> zom_50mg "Zom 50mg" 0.97in left #> zom_100mg "Zom 100mg" 0.97in left #> total "Total" 0.97in left #> group "Group" 0.90in left #> Header: valign=bottom  ## ── Tidyselect formula (apply config to multiple columns) ────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic", width = 2.5),     c(zom_50mg, zom_100mg) ~ fr_col(width = 1.5, align = "right"),     starts_with("t") ~ fr_col(width = 1.5, align = "right")   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.50in left #> placebo "placebo" 0.97in left #> zom_50mg "" 1.50in right #> zom_100mg "" 1.50in right #> total "" 1.50in right #> group "group" 0.90in left #> Header: valign=bottom  ## ── Pre-formatted labels via .list ───────────────────────────────────────  labels_vec <- c(placebo = "Placebo", zom_50mg = "Zom 50mg") tbl_demog |>   fr_table() |>   fr_cols(.list = labels_vec) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "characteristic" 2.70in left #> placebo "Placebo" 0.97in left #> zom_50mg "Zom 50mg" 0.97in left #> zom_100mg "zom_100mg" 0.97in left #> total "total" 0.97in left #> group "group" 0.90in left #> Header: valign=bottom  ## ── N-count formatting via fr_header ────────────────────────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic", width = 2.5),     zom_50mg       = fr_col("Zomerane 50 mg", align = "right"),     placebo        = fr_col("Placebo", align = "right")   ) |>   fr_header(     n = c(zom_50mg = 45, placebo = 45),     format = "{name}
(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.50in left #> placebo "Placebo" 0.97in right #> zom_50mg "Zomerane 50 mg" 1.20in right #> zom_100mg "zom_100mg" 0.97in left #> total "total" 0.97in left #> group "group" 0.90in left #> Header: valign=bottom, N-counts  ## ── Combine auto-width + label transform ─────────────────────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic"),     .width = "auto",     .label_fn = ~ tools::toTitleCase(gsub("_", " ", .x))   ) |>   fr_header(     n = c(zom_50mg = 45, zom_100mg = 45, placebo = 45, total = 135),     format = "{name}
(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.70in left #> placebo "Placebo" 0.97in left #> zom_50mg "Zom 50mg" 0.97in left #> zom_100mg "Zom 100mg" 0.97in left #> total "Total" 0.97in left #> group "Group" 0.90in left #> Header: valign=bottom, N-counts  ## ── Column splitting: split + fit to fill page ─────────────────────────  tbl_vs |>   fr_table() |>   fr_cols(     param     = fr_col("Parameter", stub = TRUE),     statistic = fr_col("Statistic", stub = TRUE),     .split = TRUE,     .width = "fit"   ) #>  #> ── fr_spec: Table  #> Data: 60 rows x 12 columns #> Page: landscape letter, 9pt Courier New #> Columns (12 visible of 12): #> param "Parameter" 1.06in left #> timepoint "timepoint" 0.55in left #> statistic "Statistic" 0.55in left #> placebo_base "placebo_base" 0.75in left #> placebo_value "placebo_value" 0.75in left #> placebo_chg "placebo_chg" 0.65in left #> zom_50mg_base "zom_50mg_base" 0.75in left #> zom_50mg_value "zom_50mg_value" 0.80in left #> ... and 4 more #> Header: valign=bottom  ## ── Column splitting with natural widths (no stretching) ────────────────  tbl_vs |>   fr_table() |>   fr_cols(.split = TRUE) #>  #> ── fr_spec: Table  #> Data: 60 rows x 12 columns #> Page: landscape letter, 9pt Courier New #> Columns (12 visible of 12): #> param "param" 1.57in left #> timepoint "timepoint" 0.82in left #> statistic "statistic" 0.82in left #> placebo_base "placebo_base" 1.12in left #> placebo_value "placebo_value" 1.12in left #> placebo_chg "placebo_chg" 0.97in left #> zom_50mg_base "zom_50mg_base" 1.12in left #> zom_50mg_value "zom_50mg_value" 1.20in left #> ... and 4 more #> Header: valign=bottom

## ── Center all headers with bottom valign ────────────────────────────────  tbl_demog |>   fr_table() |>   fr_header(align = "center", valign = "bottom", bold = TRUE) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Header: bold, valign=bottom, align=center  ## ── Global N-count (same for all groups) ─────────────────────────────────  tbl_demog |>   fr_table() |>   fr_cols(     characteristic = fr_col("Characteristic", width = 2.5),     zom_50mg       = fr_col("Zomerane 50 mg", align = "right"),     placebo        = fr_col("Placebo", align = "right")   ) |>   fr_header(     n = c(zom_50mg = 45, placebo = 45),     format = "{name}
(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "Characteristic" 2.50in left #> placebo "Placebo" 0.97in right #> zom_50mg "Zomerane 50 mg" 1.20in right #> zom_100mg "zom_100mg" 0.97in left #> total "total" 0.97in left #> group "group" 0.90in left #> Header: valign=bottom, N-counts  ## ── Per-group N-count (different N per page_by group) ────────────────────  # Hardcode N per parameter — each page_by group shows its own N tbl_vs |>   fr_table() |>   fr_rows(page_by = "param") |>   fr_header(     n = list(       "Systolic BP (mmHg)"  = c(placebo = 45, zom_50mg = 45, zom_100mg = 39, total = 129),       "Heart Rate (bpm)"    = c(placebo = 45, zom_50mg = 38, zom_100mg = 40, total = 123),       "Temperature (C)"     = c(placebo = 42, zom_50mg = 39, zom_100mg = 37, total = 118)     ),     format = "{name}
(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 60 rows x 12 columns #> Page: landscape letter, 9pt Courier New #> Header: valign=bottom, N-counts #> Rows: page_by=param  ## ── Function N-count (dynamic from record-level source) ──────────────────  # Best approach for long-format source data (CDISC ADaM pattern): # the function receives the per-group subset of n_data and computes # N per treatment arm dynamically. # # group_data = rows of advs where PARAM matches the current page_by value # group_label = the page_by label string (unused here — counting logic #               is the same for all parameters, only the data subset changes) tbl_vs |>   fr_table() |>   fr_rows(page_by = "param") |>   fr_header(     n = function(group_data, group_label) {       d <- group_data       c(placebo   = length(unique(d$USUBJID[d$TRTA == "Placebo"])),         zom_50mg  = length(unique(d$USUBJID[d$TRTA == "Zomerane 50mg"])),         zom_100mg = length(unique(d$USUBJID[d$TRTA == "Zomerane 100mg"])),         total     = length(unique(d$USUBJID)))     },     n_data = advs,     format = "{name}
(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 60 rows x 12 columns #> Page: landscape letter, 9pt Courier New #> Header: valign=bottom, N-counts #> Rows: page_by=param  ## ── Function N-count using group_label for conditional logic ──────────────  # group_label is useful when counting logic varies by parameter. # Here, Temperature uses a stricter filter (non-missing + in-range). tbl_vs |>   fr_table() |>   fr_rows(page_by = "param") |>   fr_header(     n = function(group_data, group_label) {       d <- group_data       if (group_label == "Temperature (C)") {         # Stricter: only subjects with in-range temperature         d <- d[d$AVAL >= 35 & d$AVAL <= 42, ]       }       c(placebo   = length(unique(d$USUBJID[d$TRTA == "Placebo"])),         zom_50mg  = length(unique(d$USUBJID[d$TRTA == "Zomerane 50mg"])),         zom_100mg = length(unique(d$USUBJID[d$TRTA == "Zomerane 100mg"])),         total     = length(unique(d$USUBJID)))     },     n_data = advs,     format = "{name}
(N={n})"   ) #>  #> ── fr_spec: Table  #> Data: 60 rows x 12 columns #> Page: landscape letter, 9pt Courier New #> Header: valign=bottom, N-counts #> Rows: page_by=param  ## ── Header background colour (hex or CSS named colour) ──────────────────  # Hex colour tbl_demog |>   fr_table() |>   fr_header(bg = "#E0E0E0", bold = TRUE) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Header: bold, valign=bottom  # CSS named colour (148 available: lavender, aliceblue, gainsboro, etc.) tbl_demog |>   fr_table() |>   fr_header(bg = "lavender", fg = "midnightblue", bold = TRUE) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Header: bold, valign=bottom  ## ── Order-independent: fr_header first, then fr_cols ─────────────────────  tbl_demog |>   fr_table() |>   fr_header(n = c(zom_50mg = 45), format = "{name}
(N={n})") |>   fr_cols(zom_50mg = fr_col("Zom 50mg", align = "right")) #>  #> ── fr_spec: Table  #> Data: 28 rows x 6 columns #> Page: landscape letter, 9pt Courier New #> Columns (6 visible of 6): #> characteristic "characteristic" 2.70in left #> placebo "placebo" 0.97in left #> zom_50mg "Zom 50mg" 0.97in right #> zom_100mg "zom_100mg" 0.97in left #> total "total" 0.97in left #> group "group" 0.90in left #> Header: valign=bottom, N-counts
